INSERT INTO `team_seasons` (`team_id`, `season_id`, `coach_person_id`, `wins`, `losses`, `points_for`, `points_against`, `point_diff`, `final_rank`, `playoff_seed`, `qualified_playin`, `qualified_playoffs`, `final_four_flag`, `avg_attendance`, `notes`) VALUES
(1, 1, 101, 19, 8, 3877, 3309, 568, 3, 3, 0, 1, 1, 5816, 'FC Barcelona secured home-court position with steady two-way play, closing at 19-8 with a +568 point differential.'),
(2, 1, 102, 24, 3, 4262, 2439, 1823, 1, 1, 0, 1, 1, 10240, 'Olympiacos Piraeus set the pace from opening night and finished clear of the field, closing at 24-3 with a +1823 point differential.'),
(3, 1, 103, 17, 10, 4290, 3682, 608, 4, 4, 0, 1, 1, 12193, 'Fenerbahce Beko Istanbul secured home-court position with steady two-way play, closing at 17-10 with a +608 point differential.'),
