-- Generated from the live archive for phpMyAdmin import.
-- Import this file into MySQL/phpMyAdmin, then export again from phpMyAdmin if your professor wants a literal phpMyAdmin export artifact.
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
DROP DATABASE IF EXISTS `euroleague`;
CREATE DATABASE `euroleague` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `euroleague`;
START TRANSACTION;

DROP TABLE IF EXISTS `people`;

CREATE TABLE `people` (
    person_id INT NOT NULL AUTO_INCREMENT,
    first_name VARCHAR(100) NOT NULL,
    last_name VARCHAR(100) NOT NULL,
    date_of_birth DATE,
    nationality VARCHAR(100),
    photo_url VARCHAR(255),
    PRIMARY KEY (person_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `countries`;

CREATE TABLE `countries` (
    country_id INT NOT NULL AUTO_INCREMENT,
    country_name VARCHAR(100) NOT NULL,
    country_code VARCHAR(3) NOT NULL,
    continent VARCHAR(50),
    PRIMARY KEY (country_id),
    UNIQUE (country_code)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `players`;

CREATE TABLE `players` (
    person_id INT NOT NULL,
    position VARCHAR(30),
    height DECIMAL(5,2),
    weight DECIMAL(6,2),
    PRIMARY KEY (person_id),
    FOREIGN KEY (person_id) REFERENCES people(person_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `coaches`;

CREATE TABLE `coaches` (
    person_id INT NOT NULL,
    experience_years SMALLINT,
    coaching_role VARCHAR(50),
    PRIMARY KEY (person_id),
    FOREIGN KEY (person_id) REFERENCES people(person_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `referees`;

CREATE TABLE `referees` (
    person_id INT NOT NULL,
    license_level VARCHAR(50),
    active_since DATE,
    federation VARCHAR(100),
    current_flag TINYINT(1) NOT NULL DEFAULT 1,
    PRIMARY KEY (person_id),
    FOREIGN KEY (person_id) REFERENCES people(person_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `arenas`;

CREATE TABLE `arenas` (
    arena_id INT NOT NULL AUTO_INCREMENT,
    arena_name VARCHAR(120) NOT NULL,
    city VARCHAR(100),
    capacity INT,
    website_url VARCHAR(255),
    country_id INT NOT NULL,
    PRIMARY KEY (arena_id),
    FOREIGN KEY (country_id) REFERENCES countries(country_id),
    CHECK (capacity IS NULL OR capacity >= 0)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `seasons`;

CREATE TABLE `seasons` (
    season_id INT NOT NULL AUTO_INCREMENT,
    season_label VARCHAR(30) NOT NULL,
    start_date DATE,
    end_date DATE,
    competition_name VARCHAR(100) NOT NULL,
    is_completed TINYINT(1) NOT NULL DEFAULT 0,
    PRIMARY KEY (season_id),
    UNIQUE (season_label)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `teams`;

CREATE TABLE `teams` (
    team_id INT NOT NULL AUTO_INCREMENT,
    country_id INT NOT NULL,
    home_arena_id INT,
    team_name VARCHAR(120) NOT NULL,
    short_name VARCHAR(50),
    nickname VARCHAR(80),
    founded_year SMALLINT,
    primary_color VARCHAR(20),
    secondary_color VARCHAR(20),
    logo_url VARCHAR(255),
    website_url VARCHAR(255),
    is_active TINYINT(1) NOT NULL DEFAULT 1,
    PRIMARY KEY (team_id),
    FOREIGN KEY (country_id) REFERENCES countries(country_id),
    FOREIGN KEY (home_arena_id) REFERENCES arenas(arena_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `team_seasons`;

CREATE TABLE `team_seasons` (
    team_id INT NOT NULL,
    season_id INT NOT NULL,
    coach_person_id INT,
    wins SMALLINT NOT NULL DEFAULT 0,
    losses SMALLINT NOT NULL DEFAULT 0,
    points_for INT NOT NULL DEFAULT 0,
    points_against INT NOT NULL DEFAULT 0,
    point_diff INT NOT NULL DEFAULT 0,
    final_rank SMALLINT,
    playoff_seed SMALLINT,
    qualified_playin TINYINT(1) NOT NULL DEFAULT 0,
    qualified_playoffs TINYINT(1) NOT NULL DEFAULT 0,
    final_four_flag TINYINT(1) NOT NULL DEFAULT 0,
    avg_attendance INT,
    notes TEXT,
    PRIMARY KEY (team_id, season_id),
    FOREIGN KEY (team_id) REFERENCES teams(team_id),
    FOREIGN KEY (season_id) REFERENCES seasons(season_id),
    FOREIGN KEY (coach_person_id) REFERENCES coaches(person_id),
    CHECK (wins >= 0),
    CHECK (losses >= 0),
    CHECK (avg_attendance IS NULL OR avg_attendance >= 0)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `roster_assignments`;

CREATE TABLE `roster_assignments` (
    team_id INT NOT NULL,
    season_id INT NOT NULL,
    person_id INT NOT NULL,
    jersey_number SMALLINT,
    role VARCHAR(50),
    start_date DATE,
    end_date DATE,
    is_active TINYINT(1) NOT NULL DEFAULT 1,
    PRIMARY KEY (team_id, season_id, person_id),
    FOREIGN KEY (team_id, season_id) REFERENCES team_seasons(team_id, season_id),
    FOREIGN KEY (person_id) REFERENCES players(person_id),
    CHECK (jersey_number IS NULL OR jersey_number >= 0)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `games`;

CREATE TABLE `games` (
    game_id INT NOT NULL AUTO_INCREMENT,
    season_id INT NOT NULL,
    home_team_id INT NOT NULL,
    away_team_id INT NOT NULL,
    referee_id INT,
    arena_id INT,
    game_date DATE NOT NULL,
    tipoff_time TIME,
    status VARCHAR(30),
    home_score SMALLINT,
    away_score SMALLINT,
    attendance INT,
    overtime_count SMALLINT NOT NULL DEFAULT 0,
    PRIMARY KEY (game_id),
    FOREIGN KEY (season_id) REFERENCES seasons(season_id),
    FOREIGN KEY (home_team_id) REFERENCES teams(team_id),
    FOREIGN KEY (away_team_id) REFERENCES teams(team_id),
    FOREIGN KEY (referee_id) REFERENCES referees(person_id),
    FOREIGN KEY (arena_id) REFERENCES arenas(arena_id),
    CHECK (home_team_id <> away_team_id),
    CHECK (attendance IS NULL OR attendance >= 0),
    CHECK (overtime_count >= 0)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `team_game_stats`;

CREATE TABLE `team_game_stats` (
    game_id INT NOT NULL,
    team_id INT NOT NULL,
    points SMALLINT NOT NULL DEFAULT 0,
    rebounds SMALLINT NOT NULL DEFAULT 0,
    assists SMALLINT NOT NULL DEFAULT 0,
    turnovers SMALLINT NOT NULL DEFAULT 0,
    fouls SMALLINT NOT NULL DEFAULT 0,
    field_goals_made SMALLINT NOT NULL DEFAULT 0,
    field_goals_attempted SMALLINT NOT NULL DEFAULT 0,
    three_points_made SMALLINT NOT NULL DEFAULT 0,
    three_points_attempted SMALLINT NOT NULL DEFAULT 0,
    free_throws_made SMALLINT NOT NULL DEFAULT 0,
    free_throws_attempted SMALLINT NOT NULL DEFAULT 0,
    PRIMARY KEY (game_id, team_id),
    FOREIGN KEY (game_id) REFERENCES games(game_id),
    FOREIGN KEY (team_id) REFERENCES teams(team_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `player_game_stats`;

CREATE TABLE `player_game_stats` (
    game_id INT NOT NULL,
    person_id INT NOT NULL,
    points SMALLINT NOT NULL DEFAULT 0,
    rebounds SMALLINT NOT NULL DEFAULT 0,
    assists SMALLINT NOT NULL DEFAULT 0,
    turnovers SMALLINT NOT NULL DEFAULT 0,
    fouls SMALLINT NOT NULL DEFAULT 0,
    field_goals_made SMALLINT NOT NULL DEFAULT 0,
    field_goals_attempted SMALLINT NOT NULL DEFAULT 0,
    three_points_made SMALLINT NOT NULL DEFAULT 0,
    three_points_attempted SMALLINT NOT NULL DEFAULT 0,
    free_throws_made SMALLINT NOT NULL DEFAULT 0,
    free_throws_attempted SMALLINT NOT NULL DEFAULT 0,
    PRIMARY KEY (game_id, person_id),
    FOREIGN KEY (game_id) REFERENCES games(game_id),
    FOREIGN KEY (person_id) REFERENCES players(person_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `awards`;

CREATE TABLE `awards` (
    award_id INT NOT NULL AUTO_INCREMENT,
    season_id INT NOT NULL,
    person_id INT NOT NULL,
    award_name VARCHAR(120) NOT NULL,
    award_type VARCHAR(50),
    notes TEXT,
    PRIMARY KEY (award_id),
    FOREIGN KEY (season_id) REFERENCES seasons(season_id),
    FOREIGN KEY (person_id) REFERENCES people(person_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `grid_puzzles`;

CREATE TABLE `grid_puzzles` (
    grid_puzzle_id INT NOT NULL AUTO_INCREMENT,
    season_id INT NOT NULL,
    puzzle_name VARCHAR(120) NOT NULL,
    puzzle_date DATE,
    status VARCHAR(30),
    PRIMARY KEY (grid_puzzle_id),
    FOREIGN KEY (season_id) REFERENCES seasons(season_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `grid_puzzle_rows`;

CREATE TABLE `grid_puzzle_rows` (
    grid_puzzle_id INT NOT NULL,
    row_position SMALLINT NOT NULL,
    team_id INT NOT NULL,
    clue_text VARCHAR(255),
    PRIMARY KEY (grid_puzzle_id, row_position),
    FOREIGN KEY (grid_puzzle_id) REFERENCES grid_puzzles(grid_puzzle_id),
    FOREIGN KEY (team_id) REFERENCES teams(team_id),
    CHECK (row_position >= 1)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `grid_puzzle_columns`;

CREATE TABLE `grid_puzzle_columns` (
    grid_puzzle_id INT NOT NULL,
    column_position SMALLINT NOT NULL,
    stat_name VARCHAR(80) NOT NULL,
    comparison_operator VARCHAR(4) NOT NULL,
    target_value DECIMAL(10,2),
    units VARCHAR(20),
    clue_text VARCHAR(255),
    PRIMARY KEY (grid_puzzle_id, column_position),
    FOREIGN KEY (grid_puzzle_id) REFERENCES grid_puzzles(grid_puzzle_id),
    CHECK (column_position >= 1),
    CHECK (comparison_operator IN ('>', '>=', '=', '<=', '<', '<>'))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `grid_puzzle_cells`;

CREATE TABLE `grid_puzzle_cells` (
    grid_puzzle_id INT NOT NULL,
    row_position SMALLINT NOT NULL,
    column_position SMALLINT NOT NULL,
    cell_value VARCHAR(100),
    notes TEXT,
    PRIMARY KEY (grid_puzzle_id, row_position, column_position),
    FOREIGN KEY (grid_puzzle_id, row_position) REFERENCES grid_puzzle_rows(grid_puzzle_id, row_position),
    FOREIGN KEY (grid_puzzle_id, column_position) REFERENCES grid_puzzle_columns(grid_puzzle_id, column_position)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `grid_puzzle_answers`;

CREATE TABLE `grid_puzzle_answers` (
    grid_puzzle_id INT NOT NULL,
    row_position SMALLINT NOT NULL,
    column_position SMALLINT NOT NULL,
    person_id INT NOT NULL,
    is_primary TINYINT(1) NOT NULL DEFAULT 0,
    notes TEXT,
    PRIMARY KEY (grid_puzzle_id, row_position, column_position, person_id),
    FOREIGN KEY (grid_puzzle_id, row_position, column_position) REFERENCES grid_puzzle_cells(grid_puzzle_id, row_position, column_position),
    FOREIGN KEY (person_id) REFERENCES players(person_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;





































































































































































































































COMMIT;
SET FOREIGN_KEY_CHECKS = 1;
